initialCss:
body {
  font-family: sans-serif;
  background-color: #0f172a;
  color: #f8fafc;
  margin: 20px;
}
.dashboard {
  max-width: 600px;
  margin: 0 auto;
  background: #1e293b;
  padding: 20px;
  border-radius: 8px;
}
.stats-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
  margin: 20px 0;
}
.stat-card {
  background: #334155;
  padding: 10px;
  border-radius: 4px;
  text-align: center;
}
.controls {
  display: flex;
  gap: 10px;
  margin-bottom: 20px;
}
input {
  flex-grow: 1;
  padding: 8px;
  border-radius: 4px;
  border: 1px solid #475569;
  background: #0f172a;
  color: #fff;
}
button {
  padding: 8px 16px;
  background: #3b82f6;
  color: #fff;
  border: none;
  border-radius: 4px;
  cursor: pointer;
}

